package model

import (
	"time"

	"github.com/google/uuid"
	"gorm.io/gorm"
)

// GeneratedFile represents a file generated by a tool execution.
type GeneratedFile struct {
	ID        string    `gorm:"type:char(36);primaryKey" json:"id"`
	ReportID  string    `gorm:"type:char(36);not null;uniqueIndex:uk_generated_file_report_name,priority:1" json:"report_id"`
	Filename  string    `gorm:"type:varchar(255);not null;uniqueIndex:uk_generated_file_report_name,priority:2" json:"filename"`
	Language  string    `gorm:"type:varchar(32)" json:"language"`
	MimeType  string    `gorm:"type:varchar(100);not null;default:'text/markdown'" json:"mime_type"`
	Content   string    `gorm:"type:longtext;not null" json:"content"`
	SizeBytes uint64    `gorm:"type:bigint unsigned;not null;default:0" json:"size_bytes"`
	CreatedAt time.Time `gorm:"not null" json:"created_at"`
}

// BeforeCreate sets UUID and timestamp before creating a generated file.
func (g *GeneratedFile) BeforeCreate(tx *gorm.DB) error {
	if g.ID == "" {
		g.ID = uuid.New().String()
	}
	g.CreatedAt = time.Now().UTC()
	return nil
}

// TableName returns the table name for GeneratedFile.
func (GeneratedFile) TableName() string {
	return "generated_files"
}
